mapper.select:
SELECT DISTINCT A.ID, A.SERVICE_NM, A.SHORT_CD, A.PROCESS_NMS, A.REMARK, A.CREATE_BY, A.CREATE_BY_NAME, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_BY_NAME, A.UPDATE_TIME, A.IN_OUT, A.IN_OUT_STORAGE FROM t_bus_service A left join t_bus_service_process C on C.BUS_SERVICE_GID=A.ID
and ID = #{id}
and (SERVICE_NM LIKE #{serviceNmLike} or SHORT_CD LIKE #{serviceNmLike})
and SHORT_CD = #{shortCd}
and PROCESS_NMS = #{processNms}
and REMARK = #{remark}
AND C.WORK_PROCESS_CD =#{workProcessCd}
